BlockManager = {}
BlockManager.BlockLifeCache = {}
BlockManager.PlayerBlockCache = {}
BlockManager.MapBlockCache = {}

function BlockManager:clearAllBlock()
    for hash, cache in pairs(BlockManager.PlayerBlockCache) do
        EngineWorld:setBlockToAir(cache.position)
    end
    BlockManager.BlockLifeCache = {}
    BlockManager.PlayerBlockCache = {}
    BlockManager.MapBlockCache = {}
end

function BlockManager:clearPlayerBlock(player)
    local removes = {}
    for hash, cache in pairs(BlockManager.PlayerBlockCache) do
        if cache.userId == player.userId then
            EngineWorld:setBlockToAir(cache.position)
            table.insert(removes, hash)
        end
    end
    for hash, cache in pairs(BlockManager.MapBlockCache) do
        if cache.userId == player.userId then
            EngineWorld:setBlock(cache.position, cache.blockId)
            table.insert(removes, hash)
        end
    end
    for _, remove in pairs(removes) do
        BlockManager.BlockLifeCache[remove] = nil
        BlockManager.PlayerBlockCache[remove] = nil
        BlockManager.MapBlockCache[remove] = nil
    end
end

function BlockManager:onPlayerPlaceBlock(player, blockId, blockPos)
    --HostApi.log("BlockManager:onPlayerPlaceBlock")
    local life = 1
    for _, block in pairs(player.equip_blocks) do
        if block.ItemId == blockId then
            life = block.Life
        end
    end
    --HostApi.log("BlockManager:onPlayerPlaceBlock life = " .. life)
    local hash = VectorUtil.hashVector3(blockPos)
    BlockManager.BlockLifeCache[hash] = life
    BlockManager.PlayerBlockCache[hash] = {
        userId = player.userId,
        position = blockPos
    }
    player.taskController:packingProgressData(player, Define.TaskType.Fright.PlaceBlock, GameMatch.gameType)
end

function BlockManager:onPlayerShootBlock(player, blockPos, blockId, gunId)
    local hash = VectorUtil.hashVector3(blockPos)
    local gun = GunConfig:getGunByItemId(gunId)
    if not gun then
        return false
    end
    local life = BlockManager.BlockLifeCache[hash]
    if not life then
        life = BlockConfig:getBlockLife(blockId)
        if life < 0 then
            return false
        end
        local cache = BlockManager.MapBlockCache[hash]
        if not cache then
            BlockManager.MapBlockCache[hash] = {
                userId = player.userId,
                position = blockPos,
                blockId = blockId,
            }
        end
    end
    life = life - gun.hurtBlock
    if life <= 0 then
        EngineWorld:setBlockToAir(blockPos)
        local pos = VectorUtil.newVector3(blockPos.x + 0.5, blockPos.y + 0.5, blockPos.z + 0.5)
        EngineWorld:addSimpleEffect("fragment_block.effect", pos, 0, 1000, 0, 2)
        BlockManager.BlockLifeCache[hash] = nil
        BlockManager.PlayerBlockCache[hash] = nil
        player.taskController:packingProgressData(player, Define.TaskType.Fright.DestroyBlock, GameMatch.gameType)
    else
        BlockManager.BlockLifeCache[hash] = life
    end
    return true
end

return BlockManager